const t=()=>{try{const e=localStorage.getItem("token");if(!e)return console.warn("No auth token found - user not logged in"),null;const n=e.split(".")[1],o=JSON.parse(atob(n)),r=o.id||o.userId||o.sub||o.user_id;return r?typeof r=="number"?r:parseInt(r,10):(console.error("No user ID found in token payload:",o),null)}catch(e){return console.error("Error decoding auth token:",e),null}};export{t as g};
